def load_config(path: str) -> List[TenantConfig]:
    with open(path, "r", encoding="utf-8") as f:
        raw = json.load(f)

    if isinstance(raw, dict) and "tenants" in raw:
        raw = raw["tenants"]

    if not isinstance(raw, list):
        raise ValueError("Configuration must be a list of tenants or an object with a 'tenants' list")

    tenants: List[TenantConfig] = []
    for item in raw:
        if "vhost" not in item:
            raise ValueError(f"Tenant entry missing 'vhost': {item}")

        users = []
        for user in item.get("users", []):
            if "name" not in user or "password" not in user:
                raise ValueError(f"User entry must include 'name' and 'password': {user}")
            permissions = dict(DEFAULT_PERMISSIONS)
            permissions.update(user.get("permissions", {}))
            users.append(
                UserConfig(
                    name=user["name"],
                    password=user["password"],
                    tags=user.get("tags", ""),
                    permissions=permissions,
                )
            )

        tenants.append(TenantConfig(vhost=item["vhost"], users=users))

    return tenants


def wait_for_api(api: RabbitMQAPI, retries: int, delay: int) -> None:
    for attempt in range(1, retries + 1):
        if api.health_check():
            return
        if attempt < retries:
            time.sleep(delay)
    raise RuntimeError("RabbitMQ Management API is not reachable after retries")


