            if existing_user is None:
                api.create_user(user.name, user.password, user.tags)
                print(f"[OK] Created user: {user.name}")
            else:
                api.create_user(user.name, user.password, user.tags)
                print(f"[OK] Updated user: {user.name}")

            api.set_permissions(
                tenant.vhost,
                user.name,
                user.permissions["configure"],
                user.permissions["write"],
                user.permissions["read"],
            )
            print(f"[OK] Set permissions for user '{user.name}' on vhost '{tenant.vhost}'")


